// Lambda@Edge — Viewer Request handler (deploy to us-east-1)
import { verify } from 'jsonwebtoken';

export const handler = async (event) => {
  const { request } = event.Records[0].cf;
  const authHeader = request.headers['authorization']?.[0]?.value ?? '';
  const token = authHeader.replace('Bearer ', '');

  try {
    verify(token, process.env.JWT_SECRET);
    return request; // Forward authenticated request to ALB/S3 origin
  } catch {
    return {
      status: '401',
      statusDescription: 'Unauthorized',
      body: JSON.stringify({ error: 'Invalid token' }),
      headers: { 'content-type': [{ key: 'Content-Type', value: 'application/json' }] },
    };
  }
};

# Deny S3 uploads without KMS encryption
aws s3api put-bucket-policy --bucket my-prod-bucket --policy '{
  "Version": "2012-10-17",
  "Statement": [{
    "Effect": "Deny",
    "Principal": "*",
    "Action": "s3:PutObject",
    "Resource": "arn:aws:s3:::my-prod-bucket/*",
    "Condition": {
      "StringNotEquals": {
        "s3:x-amz-server-side-encryption": "aws:kms"
      }
    }
  }]
}'

# Enforce allowed regions via AWS Organizations SCP (JSON policy)
aws organizations create-policy \
  --name "EnforceApprovedRegions" \
  --type SERVICE_CONTROL_POLICY \
  --description "Restrict resource creation to approved regions" \
  --content '{
    "Version": "2012-10-17",
    "Statement": [{
      "Effect": "Deny",
      "Action": "*",
      "Resource": "*",
      "Condition": {
        "StringNotEquals": {
          "aws:RequestedRegion": ["us-east-1", "eu-west-1", "ap-southeast-1"]
        }
      }
    }]
  }'

import boto3

client = boto3.client('ce', region_name='us-east-1')

response = client.get_anomalies(
    DateInterval={
        'StartDate': '2026-04-10',
        'EndDate': '2026-04-17'
    },
    TotalImpact={
        'NumericOperator': 'GREATER_THAN',
        'StartValue': 50.0  # only anomalies costing >$50
    }
)

for anomaly in response['Anomalies']:
    print(anomaly['AnomalyId'], anomaly['Impact']['TotalImpact'], anomaly['RootCauses'])
